func (a *adapter) UpsertAppConfiguration(ctx context.Context, input custominvoicing.UpsertAppConfigurationInput) error {
	return entutils.TransactingRepoWithNoValue(ctx, a, func(ctx context.Context, tx *adapter) error {
		return tx.db.AppCustomInvoicing.Create().
			SetID(input.AppID.ID).
			SetNamespace(input.AppID.Namespace).
			SetEnableDraftSyncHook(input.Configuration.EnableDraftSyncHook).
			SetEnableIssuingSyncHook(input.Configuration.EnableIssuingSyncHook).
			OnConflictColumns(appcustominvoicing.FieldID, appcustominvoicing.FieldNamespace).
			UpdateNewValues().
			Exec(ctx)
	})
}

func (h *handler) DraftSyncronized() DraftSyncronizedHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, params DraftSyncronizedParams) (DraftSyncronizedRequest, error) {
			namespace, err := h.resolveNamespace(ctx)
			if err != nil { return DraftSyncronizedRequest{}, fmt.Errorf("failed to resolve namespace: %w", err) }
			var body api.CustomInvoicingDraftSynchronizedRequest
			if err := commonhttp.JSONRequestBodyDecoder(r, &body); err != nil { return DraftSyncronizedRequest{}, err }
			return DraftSyncronizedRequest{InvoiceID: billing.InvoiceID{ID: params.InvoiceID, Namespace: namespace}, UpsertInvoiceResults: mapUpsertStandardInvoiceResultFromAPI(body.Invoicing)}, nil
		},
		func(ctx context.Context, request DraftSyncronizedRequest) (DraftSyncronizedResponse, error) {
			if err := request.Validate(); err != nil { return DraftSyncronizedResponse{}, err }
			invoice, err := h.service.SyncDraftInvoice(ctx, request)
			if err != nil { return DraftSyncronizedResponse{}, err }
			return billinghttpdriver.MapStandardInvoiceToAPI(invoice)
		},
		commonhttp.JSONResponseEncoderWithStatus[DraftSyncronizedResponse](http.StatusOK),
		httptransport.AppendOptions(h.options, httptransport.WithOperationName("DraftSyncronized"), httptransport.WithErrorEncoder(errorEncoder()))...,
	)
}

func (s *Service) HandlePaymentTrigger(ctx context.Context, input appcustominvoicing.HandlePaymentTriggerInput) (billing.StandardInvoice, error) {
	if err := input.Validate(); err != nil { return billing.StandardInvoice{}, err }
	return transaction.Run(ctx, s.adapter, func(ctx context.Context) (billing.StandardInvoice, error) {
		invoice, err := s.billingService.GetStandardInvoiceById(ctx, billing.GetStandardInvoiceByIdInput{Invoice: input.InvoiceID})
		if err != nil { return billing.StandardInvoice{}, err }
		if err := s.ValidateInvoiceApp(invoice); err != nil { return billing.StandardInvoice{}, err }
		err = s.billingService.TriggerInvoice(ctx, billing.InvoiceTriggerServiceInput{
			InvoiceTriggerInput: billing.InvoiceTriggerInput{Invoice: input.InvoiceID, Trigger: input.Trigger},
			AppType: app.AppTypeCustomInvoicing, Capability: app.CapabilityTypeCollectPayments,
		})
		if err != nil { return billing.StandardInvoice{}, err }
		invoice, err = s.billingService.GetStandardInvoiceById(ctx, billing.GetStandardInvoiceByIdInput{Invoice: input.InvoiceID})
		if err != nil { return billing.StandardInvoice{}, err }
		if len(invoice.ValidationIssues) > 0 {
			criticalIssues := lo.Filter(invoice.ValidationIssues, func(issue billing.ValidationIssue, _ int) bool { return issue.Severity == billing.ValidationIssueSeverityCritical })
			if len(criticalIssues) > 0 { return billing.StandardInvoice{}, billing.ValidationError{Err: criticalIssues.AsError()} }
		}
		return invoice, nil
	})
}
